+    #[test]
+    fn save_restore_initial_state_is_zero() {
+        let dec = UnvisDecoder::new();
+        assert_eq!(dec.save_state(), 0);
+        let restored = UnvisDecoder::from_saved_state(0);
+        assert_eq!(restored, UnvisDecoder::new());
